/**
 * Get the correct public URL for assets, accounting for the app's base path
 * in production (GitHub Pages subdirectory)
 */
export const getPublicUrl = (path: string): string => {
  // PUBLIC_URL est défini par react-scripts au build time à partir de "homepage" dans package.json
  // Il sera soit vide ('') en dev, soit '/pkr' en production
  const publicUrl = process.env.PUBLIC_URL || '';
  const cleanPath = path.startsWith('/') ? path : `/${path}`;
  const fullUrl = `${publicUrl}${cleanPath}`;
  return fullUrl;
};
